class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        self.cache = {}

    def get_cache(self, index_file):
        if index_file not in self.cache:
            cache_file = os.path.join(self.cache_dir, f"{index_file}.cache")
            if os.path.exists(cache_file):
                with open(cache_file, 'rb') as f:
                    self.cache[index_file] = f.read()
            else:
                self.cache[index_file] = None
        return self.cache[index_file]

    def set_cache(self, index_file, value):
        cache_file = os.path.join(self.cache_dir, f"{index_file}.cache")
